import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";


const FAQS = [
  { q: "What is the Pythagorean theorem?", a: "For a right triangle: a squared + b squared = c squared, where c is the hypotenuse. If you know two sides, solve for the third. Classic examples include 3-4-5, 5-12-13, and 8-15-17. The theorem only applies to right triangles." },
  { q: "How do I find the area of a triangle?", a: "There are several formulas: base-height area = 0.5 x base x height, Heron's formula uses only side lengths, and the SAS formula uses two sides and the included angle. This calculator uses Heron's formula from three sides." },
  { q: "What is the Law of Cosines?", a: "The Law of Cosines is c squared = a squared + b squared - 2ab cos(C), where C is the angle opposite side c. It generalizes the Pythagorean theorem for any triangle and can find angles from three side lengths." },
  { q: "What is the Law of Sines?", a: "a/sin(A) = b/sin(B) = c/sin(C). The ratio of each side to the sine of its opposite angle is constant. Use it when you know: (1) two angles and one side (AAS/ASA), or (2) two sides and an angle opposite one of them (SSA - the 'ambiguous case' that can have 0, 1, or 2 solutions). Complements the Law of Cosines." },
  { q: "What makes a valid triangle?", a: "The triangle inequality theorem says the sum of any two sides must be greater than the third side. For sides a, b, c: a+b > c, a+c > b, and b+c > a. All angles must sum to exactly 180 degrees and all sides must be positive." },
  { q: "What is the difference between acute, right, and obtuse triangles?", a: "An acute triangle has all three angles under 90 degrees. A right triangle has exactly one 90 degree angle. An obtuse triangle has one angle over 90 degrees. You can determine the type using the largest angle." },
  { q: "What is an equilateral triangle?", a: "An equilateral triangle has all three sides equal and all three angles equal, each exactly 60 degrees. It is the most symmetric triangle, and equilateral triangles are always acute." },
  { q: "What is Heron's formula and when is it useful?", a: "Heron's formula calculates triangle area from only the three side lengths, without needing height. First find the semi-perimeter s = (a+b+c)/2, then calculate the square root of s(s-a)(s-b)(s-c)." },
];

const SPECIAL_TRIANGLES = [
  ["3-4-5", "Right", "5.0", "6.000", "90, 53.13, 36.87 deg"],
  ["5-12-13", "Right", "13.0", "30.000", "90, 67.38, 22.62 deg"],
  ["5-5-5", "Equilateral", "5.0", "10.825", "60, 60, 60 deg"],
  ["6-8-10", "Right", "10.0", "24.000", "90, 53.13, 36.87 deg"],
  ["7-24-25", "Right", "25.0", "84.000", "90, 73.74, 16.26 deg"],
  ["8-8-8", "Equilateral", "8.0", "27.712", "60, 60, 60 deg"],
  ["10-10-12", "Isosceles", "12.0", "48.000", "73.74, 73.74, 32.52 deg"],
];

export default function TriangleCalculator() {
  const [sideA, setSideA] = useState(3);
  const [sideB, setSideB] = useState(4);
  const [sideC, setSideC] = useState(5);

  const a = sideA, b = sideB, c = sideC;
  const isValid = a + b > c && a + c > b && b + c > a && a > 0 && b > 0 && c > 0;

  const s = (a + b + c) / 2;
  const area = isValid ? Math.sqrt(s * (s - a) * (s - b) * (s - c)) : 0;
  const perimeter = a + b + c;
  const angleA = isValid ? Math.acos((b * b + c * c - a * a) / (2 * b * c)) * (180 / Math.PI) : 0;
  const angleB = isValid ? Math.acos((a * a + c * c - b * b) / (2 * a * c)) * (180 / Math.PI) : 0;
  const angleC = isValid ? 180 - angleA - angleB : 0;
  const isRight = Math.abs(angleA - 90) < 0.01 || Math.abs(angleB - 90) < 0.01 || Math.abs(angleC - 90) < 0.01;
  const isEquilateral = Math.abs(a - b) < 0.01 && Math.abs(b - c) < 0.01;
  const isIsosceles = !isEquilateral && (Math.abs(a - b) < 0.01 || Math.abs(b - c) < 0.01 || Math.abs(a - c) < 0.01);
  const typeLabel = isEquilateral ? "Equilateral" : isIsosceles ? "Isosceles" : "Scalene";
  const typeLabel2 = isRight ? " - Right" : angleA > 90 || angleB > 90 || angleC > 90 ? " - Obtuse" : " - Acute";
  const inradius = isValid ? area / s : 0;
  const circumradius = isValid ? (a * b * c) / (4 * area) : 0;

  return (
    <>
      <SEOHead
        title="Free Triangle Calculator Online - Calculate Area Perimeter and Angles Instantly | CalcHive"
        description="Free online triangle calculator. Calculate triangle area, perimeter and all three angles from side lengths instantly. 100% free for students and teachers, no signup required."
        canonical="/triangle-calculator"
        keywords="free triangle calculator, triangle area calculator free online, calculate triangle angles free, triangle perimeter calculator free, geometry triangle calculator free"
        category="Math Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Triangle Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free triangle calculator to calculate triangle angles free plus area and perimeter from side lengths. This triangle area calculator free online also works as a triangle perimeter calculator free and geometry triangle calculator free.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-6 mb-8">
            <SliderInput id="side-a" label="Side a" value={sideA} min={0.1} max={100} step={0.1} onChange={setSideA} format={v => `${v.toFixed(1)}`} testId="input-a" />
            <SliderInput id="side-b" label="Side b" value={sideB} min={0.1} max={100} step={0.1} onChange={setSideB} format={v => `${v.toFixed(1)}`} testId="input-b" />
            <SliderInput id="side-c" label="Side c" value={sideC} min={0.1} max={100} step={0.1} onChange={setSideC} format={v => `${v.toFixed(1)}`} testId="input-c" />
          </div>
          {isValid ? (
            <motion.div key={`${sideA}-${sideB}-${sideC}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
              <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 mb-4 text-center shadow-lg">
                <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Area</p>
                <p className="text-6xl font-black text-white tracking-tight" data-testid="result-area">{area.toFixed(4)}</p>
                <p className="text-white/70 text-sm mt-1">{typeLabel}{typeLabel2}</p>
              </div>
              <div className="grid grid-cols-3 gap-3">
                {[
                  { label: "Perimeter", value: perimeter.toFixed(3) },
                  { label: "Angle A", value: `${angleA.toFixed(2)} deg` },
                  { label: "Angle B", value: `${angleB.toFixed(2)} deg` },
                  { label: "Angle C", value: `${angleC.toFixed(2)} deg` },
                  { label: "Inradius", value: inradius.toFixed(4) },
                  { label: "Circumradius", value: circumradius.toFixed(4) },
                ].map(({ label, value }) => (
                  <div key={label} className="bg-accent/60 border border-border rounded-xl p-3 text-center hover:shadow-sm transition-shadow">
                    <p className="text-xs text-muted-foreground font-medium mb-0.5">{label}</p>
                    <p className="text-base font-extrabold text-foreground">{value}</p>
                  </div>
                ))}
              </div>
            </motion.div>
          ) : <p className="text-center text-muted-foreground py-4 bg-red-50 dark:bg-red-950/30 rounded-xl">Invalid triangle - the sum of any two sides must be greater than the third side.</p>}
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Triangle Area and Perimeter for Free</h2>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Area (Heron's) = sqrt(s(s-a)(s-b)(s-c)), s = (a+b+c)/2</p>
            <p>Angle A (Law of Cosines) = arccos((b^2 + c^2 - a^2) / 2bc)</p>
            <p>Perimeter = a + b + c</p>
            <p>Inradius = Area / s</p>
            <p>Circumradius = (a  x  b  x  c) / (4  x  Area)</p>
            <p className="text-xs text-muted-foreground mt-2">Valid triangle: a+b &gt; c, a+c &gt; b, b+c &gt; a</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How to Find All Angles of a Triangle from Side Lengths</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Sides (a-b-c)", "Type", "Hypotenuse / Longest", "Area", "Angles"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {SPECIAL_TRIANGLES.map(([sides, type, longest, area_, angles]) => (
                  <tr key={sides} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-bold text-amber-600 dark:text-amber-400 font-mono">{sides}</td>
                    <td className="py-2.5 px-4 text-foreground font-semibold">{type}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{longest}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{area_}</td>
                    <td className="py-2.5 px-4 text-muted-foreground text-xs">{angles}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">Free Geometry Triangle Tool for Students</h2>
          <p className="text-muted-foreground leading-relaxed">Use this free tool on any device to solve the calculation instantly, check your work, and get a clear result without downloads or signup.</p>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/triangle-calculator" headingLevel="h3" />
      </main>
    </>
  );
}



